<div class="table-responsive"><table class="table align-middle"><thead><tr><th>Data</th><th>Requisitante</th><th>Equipa</th><th>Artigo</th><th>Armazém</th><th>Qtd</th><th>Estado</th><th>Valor</th><th>Ações</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= htmlspecialchars(substr($r['created_at'],0,10)) ?></td><td><?= htmlspecialchars($r['requester']) ?></td><td><?= htmlspecialchars($r['team']) ?></td><td><?= htmlspecialchars($r['item']) ?></td><td><?= htmlspecialchars($r['warehouse'] ?? '-') ?></td><td><?= htmlspecialchars($r['quantity']) ?></td><td><span class="badge text-bg-info"><?= htmlspecialchars($r['status']) ?></span></td><td>€ <?= number_format((float)$r['request_value'],2,',','.') ?></td><td><div class="btn-group btn-group-sm"><a class="btn btn-outline-success" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=approve">Aprovar</a><a class="btn btn-outline-primary" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=deliver">Entregar</a><a class="btn btn-outline-secondary" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=cancel">Cancelar</a></div></td></tr><?php endforeach; ?></tbody></table></div>
